import{_ as e,o as r,c as a,ae as t}from"./chunks/framework.BzQXgbNp.js";const b=JSON.parse('{"title":"🖥️ 網頁版儀表板使用指南 (Web Dashboard)","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Dashboard.md","filePath":"Web-Dashboard.md"}'),l={name:"Web-Dashboard.md"};function n(s,o,i,d,c,h){return r(),a("div",null,[...o[0]||(o[0]=[t('<h1 id="🖥️-網頁版儀表板使用指南-web-dashboard" tabindex="-1">🖥️ 網頁版儀表板使用指南 (Web Dashboard) <a class="header-anchor" href="#🖥️-網頁版儀表板使用指南-web-dashboard" aria-label="Permalink to &quot;🖥️ 網頁版儀表板使用指南 (Web Dashboard)&quot;">​</a></h1><p>Craft-Core 提供全功能網頁儀表板，支援跨平台即時查詢伺服器經濟、個人資產、活動專區、傳送點與遊戲即時狀態。</p><hr><h2 id="🔑-1-帳號登入與安全綁定" tabindex="-1">🔑 1. 帳號登入與安全綁定 <a class="header-anchor" href="#🔑-1-帳號登入與安全綁定" aria-label="Permalink to &quot;🔑 1. 帳號登入與安全綁定&quot;">​</a></h2><ol><li>點選網頁右上角的 <strong><code>[ 以 Discord 帳號登入 ]</code></strong> 按鈕。</li><li>授權登入後，系統會自動尋找您在遊戲內綁定的 Minecraft 角色。</li><li><strong>未綁定提示</strong>：若您的帳號尚未綁定，請先登入遊戲內，輸入 <code>/discord link</code> 獲取一組 6 位數驗證碼，並至官方 Discord 私訊機器人進行綁定。</li></ol><hr><h2 id="🏠-2-首頁核心看板與活動橫幅" tabindex="-1">🏠 2. 首頁核心看板與活動橫幅 <a class="header-anchor" href="#🏠-2-首頁核心看板與活動橫幅" aria-label="Permalink to &quot;🏠 2. 首頁核心看板與活動橫幅&quot;">​</a></h2><p>登入網頁首頁後，您可以直觀查閱以下即時數據：</p><ul><li><strong>🎪 伺服器熱門活動 Alert Banner</strong>：首頁頂部自動浮現進行中的伺服器活動，包含活動主題、規則、時間與一鍵跳轉按鈕。</li><li><strong>💰 全服流通金幣</strong>：目前伺服器中所有玩家持有的金幣總額。</li><li><strong>🏛️ 累計收繳稅額</strong>：顯示商店交易已被系統回收並銷毀的 5% 印花稅金幣總量。</li><li><strong>🏪 營運中箱子商店</strong>：當前全伺服器正在營業的玩家商店總數量。</li><li><strong>🟢 遊戲即時狀態</strong>：線上/離線燈號、遊戲內座標 (X, Y, Z)、即時金幣餘額與伺服器 TPS (滿分 20.00)。</li><li><strong>🏆 富豪排行榜</strong>：顯示全服金幣餘額前 10 名的玩家排行榜與皮膚頭像。</li><li><strong>🛒 即時交易動態</strong>：免重新整理，即時推播全服最新的商店成交紀錄。</li></ul><hr><h2 id="🎪-3-伺服器活動專區-events" tabindex="-1">🎪 3. 伺服器活動專區 (<code>/events</code>) <a class="header-anchor" href="#🎪-3-伺服器活動專區-events" aria-label="Permalink to &quot;🎪 3. 伺服器活動專區 (`/events`)&quot;">​</a></h2><ul><li><strong>活動總覽</strong>：瀏覽限時活動卡片，顯示 <code>🟢 限時進行中</code>、<code>⏸️ 暫停</code>、<code>⚪ 已結束</code> 狀態。</li><li><strong>活動詳情與獎勵</strong>：查閱活動細節、起訖時間與豐厚活動獎勵說明。</li><li><strong>管理員建立與維護</strong>：管理員可線上發布新活動、切換活動狀態或編輯條款。</li></ul><hr><h2 id="🧭-4-傳送點與設施審核-teleports" tabindex="-1">🧭 4. 傳送點與設施審核 (<code>/teleports</code>) <a class="header-anchor" href="#🧭-4-傳送點與設施審核-teleports" aria-label="Permalink to &quot;🧭 4. 傳送點與設施審核 (`/teleports`)&quot;">​</a></h2><ul><li><strong>🏠 我的家園 (Homes)</strong>：列出名下的所有家園儲存點、座標、世界維度，支援一鍵安全刪除。</li><li><strong>🏁 公共地標 (Warps)</strong>：列出全服公共地標座標與維度，管理員可遠端刪除地標。</li><li><strong>📍 設施審核 (Submissions)</strong>：玩家可線上提交新建刷鐵機、公共農場等設施資料，管理員可直接在線上進行 <code>✅ 核准</code> 與 <code>❌ 駁回</code>。</li></ul><hr><h2 id="🤖-5-假人控制面板-fake-player-control" tabindex="-1">🤖 5. 假人控制面板 (Fake Player Control) <a class="header-anchor" href="#🤖-5-假人控制面板-fake-player-control" aria-label="Permalink to &quot;🤖 5. 假人控制面板 (Fake Player Control)&quot;">​</a></h2><ul><li><strong>召喚與下線</strong>：輸入名稱（系統自動帶上 <code>fp_</code> 前綴），點擊一鍵將假人召喚上線或下線（召喚時本人需在線上）。</li><li><strong>動作指令</strong>：包含連續攻擊 (Attack)、右鍵使用 (Use)、跳躍 (Jump)、蹲下 (Sneak)、疾跑 (Sprint) 與物品丟棄等全套按鈕遙控。</li></ul><hr><h2 id="📦-6-郵局與背包-inventory" tabindex="-1">📦 6. 郵局與背包 (<code>/inventory</code>) <a class="header-anchor" href="#📦-6-郵局與背包-inventory" aria-label="Permalink to &quot;📦 6. 郵局與背包 (`/inventory`)&quot;">​</a></h2><ul><li><strong>背包物品預覽</strong>：線上預覽您當前角色的 36 格背包與裝備物品。</li><li><strong>離線快遞與轉帳</strong>：線上將物品包裹或金幣匯款寄送給線上/離線玩家，收件人下次登入遊戲時自動簽收！</li></ul>',21)])])}const u=e(l,[["render",n]]);export{b as __pageData,u as default};
